import math
class Solution:
    def memLeak(self, memory1, memory2):
        t = 1
        while max(memory1, memory2) >= t:
            if memory1 >= memory2:
                memory1 -= t
            else:
                memory2 -= t
            t += 1
        return [t, memory1, memory2]

